>>> CONSTANTES >>>GCTXF	=	'N!2^7		; fonte du texte  N(F)12GCTXS	=	2^BGCFIX	; style/chasse du texteGCTXT	=	12		; taille du texteGCICF	=	'I		; fonte des icnes  IDP20GCICS	=	'D		; style/chasse des icnesGCICT	=	20		; taille des icnes>>> VARIABLES >>>OBUGC:	.BLKB	LGGC*MAXGC	; table des gnrateurs de caractresOGCLIST:.BLKB	MAXGENC*3	; liste des gencars contenus sur disqueOFAGC:	.BLKB	4		; fanions pour dbox des gencars>>> INITIALISATION >>>	LOAD.B	(A6)+OGCLIST,#-1	et mettre tout le contenu de OBUGC  zro !;-----------\\; DBOXGENCAR >;===========/; Dialogue pour la DBOX des gencars.; in	-; out	D7.W	erreur; mod	D7.WDBOXGENCAR:	PUSHM.L	D0..D5,A0..A510$:	LOAD.L	D4,(A6)+OFAGC	; D4 <-- fanions	LOAD.L	A4,#(A6)+OBUGC	; A4 <-- ^buffer des gencars	LOAD.L	A5,#(A6)+OGCLIST; A5 <-- ^liste des gencars sur disque	LOAD.W	D5,#MAXGENC*3	; D5 <-- lg pour la liste	LOAD.L	D1,#H'10000*GCTXF+H'100*GCTXS+GCTXT	LOAD.W	D2,#2^BDBSAV	; D2 <-- mode	LOAD.L	A2,(A6)+OPDDIS	; A2 <-- ^descripteur de la fentre	.W	DGENC_MODIF	; modifie un/qq gencar(s) ...	JUMP',NE 90$	LOAD.L	(A6)+OFAGC,D4	; mm. derniers fanions utiliss	COMP.W	D3,#F1		; MODIFIE ?	JUMP,EQ 10$	COMP.W	D3,#F4		; SUPPRIME ?	JUMP',NE 90$	LOAD.L	D4,#H'10000*GCTXF+H'100*GCTXS+GCTXT	LOAD.L	A3,#(A6)+OBUGC	.W	DGENC_KILL	; libre le gencar	JUMP	10$90$:	PUSH.W	D7	CALL	AFMENU		; refait les soft-keys	POP.W	D7	POPM.L	D0..D5,A0..A5	TEST.W	D7		; retour EQ/NE	RET;----------\\; DEFGENCAR >;==========/; Utilise tous les gencars par dfaut.; in	-; out	-; mod	D7.WDEFGENCAR:	PUSHM.L	D3,D4,A2..A5	LOAD.L	A5,#R16"TGDEF	LOAD.L	A4,#(A6)+OBUGC	LOAD.B	D3,#2^BGCPROT20$:	TEST.B	(A5)		; fin de la table ?	JUMP',EQ 90$		; oui => 90$				; non =>	LOAD.L	A3,#(A4)+OGCTIT30$:	LOAD.B	(A3+),(A5+)	; OBUGC <-- titre	JUMP,NE 30$	LOAD.B	(A4)+OGCFLG,D3	LOAD.B	(A4)+OGCF,(A5+)	; OBUGC <-- fonte	LOAD.B	(A4)+OGCS,(A5+)	; OBUGC <-- style	LOAD.B	(A4)+OGCT,(A5+)	; OBUGC <-- taille	LOAD.L	A2,(A6)+OPDDIS	; A2 <-- ^descripteur de la fentre	LOAD.L	D4,#H'10000*GCTXF+H'100*GCTXS+GCTXT	LOAD.L	A3,#(A6)+OBUGC	.W	DGENC_NEW	LOAD.L	A4,#(A4)+LGGC	; A4 <-- suivant dans OBUGC	CLR.B	D3		; D3 <-- protection seulement pour 1er	JUMP	20$90$:	POPM.L	D3,D4,A2..A5	RET;--------\\; GETPGC  >;========/; Donne le pointeur dans OBUGC au gencar actullement utilis.; in	-; out	A4.L	^dans OBUGC; mod	A4.LGETPGC:	PUSHM.L	D3,D4	LOAD.L	D4,(A6)+OFAGC	; D4 <-- fanions dbox gencar	JUMP',EQ 50$	LOAD.W	D3,#-120$:	INC.W	D3		; D3 <-- compte le rang du bit dans D4	RR.L	D4	JUMP,CC 20$	LOAD.L	A4,#(A6)+OBUGC	MUL.WU	D3,#LGGC	ADD.L	A4,D3	TEST.B	(A4)+OGCFLG:#BGCUSE ; gencar utilis ?	JUMP',BS 90$		; oui => 90$50$:	LOAD.L	A4,#(A6)+OBUGC	; A4 <-- prend "Fond"90$:	POPM.L	D3,D4	RETTGDEF:	.ASCIZ	"Fond"	.B	GCTXF,GCTXS,GCTXT	.IF	DESSIN	.ASCIZ	"Petit"	.B	'N!2^7,2^BGCFIX,07	.ASCIZ	"Univers"	.B	'U!2^7,0,09	.ASCIZ	"Times"	.B	'T!2^7,0,14	.ASCIZ	"Gothique"	.B	'O!2^7,0,24	.ENDIF	.B	0	.EVEN